<!-- /wp:group -->','editor-text-editor-e5c042f'=>'<p>尖沙咀-红磡海滨长廊是一条长达 3.5 公里的沿岸观景步道，沿途可饱览维多利亚港的壮丽景色和香港岛的壮观天际线。我们的志愿者从尖沙咀天星码头出发，捡拾海滨长廊上的每一个烟头垃圾。他们小心翼翼地将烟蒂尽可能多地清理掉，甚至还清理了码头的阶梯，以防止有毒的烟蒂垃圾被冲入我们的海港。我们相信，清理烟头垃圾也有助于创建一个温馨美丽的城市。   </p>
<p>我们非常欣赏 "屁股大扫除 "活动的宗旨--在美化城市的同时促进社区的健康和保健。这是一次非常有意义的活动。我们要感谢我们的员工，是他们让这次活动成为一次宝贵的经历。伟大的团队合作发挥到了极致--收集了数百个烟头。我们每个人都可以为这座美丽的城市带来改变--只要我们愿意为社区服务并相互联系。    </p>','https://eji.com.hk/our-sustainability-journey/'=>'https://eji.com.hk/zh-hans/%e6%88%91%e4%bb%ac%e7%9a%84%e5%8f%af%e6%8c%81%e7%bb%ad%e5%8f%91%e5%b1%95%e4%b9%8b%e6%97%85/','https://vimeo.com/235215203'=>'https://vimeo.com/235215203','https://www.dailymotion.com/video/x6tqhqb'=>'https://www.dailymotion.com/video/x6tqhqb','https://youtu.be/YH0N6_qiVwA'=>'https://youtu.be/YH0N6_qiVwA','text-button-4e6b7d8'=>'我们的可持续发展之旅','url-button-4e6b7d8'=>'https://eji.com.hk/zh-hans/%e6%88%91%e4%bb%ac%e7%9a%84%e5%8f%af%e6%8c%81%e7%bb%ad%e5%8f%91%e5%b1%95%e4%b9%8b%e6%97%85/','vimeo_url-video-0011d75'=>'https://vimeo.com/235215203','youtube_url-video-0011d75'=>'https://youtu.be/YH0N6_qiVwA']];
